import React from 'react';
import './Projects.css';

const Projects = () => {
  const projects = [
    {
      title: "VERA Fashion Shopping App UI",
      description: "Modern e-commerce mobile application with intuitive user flow and engaging visual design.",
      tags: ["Mobile UI", "E-commerce", "Fashion"],
      icon: "🛍️"
    },
    {
      title: "Plant Shop Mobile App",
      description: "Clean and minimalist plant shopping experience with product discovery features.",
      tags: ["Mobile App", "E-commerce", "Nature"],
      icon: "🌱"
    },
    {
      title: "Sofar Service Website UI",
      description: "Professional service platform with streamlined user journey and modern aesthetics.",
      tags: ["Web UI", "Service Design", "B2B"],
      icon: "💼"
    },
    {
      title: "Dashboard UI Concept",
      description: "Data-driven dashboard with complex information architecture and visual hierarchy.",
      tags: ["Dashboard", "Data Viz", "Analytics"],
      icon: "📊"
    }
  ];

  return (
    <section className="projects" id="projects">
      <div className="projects-container">
        <div className="section-header">
          <h2 className="section-title">Portfolio</h2>
          <div className="title-underline"></div>
        </div>

        <div className="projects-content">
          <div className="projects-grid">
            {projects.map((project, index) => (
              <div key={index} className="project-card">
                <div className="card-glow"></div>
                <div className="project-header">
                  <div className="project-icon">{project.icon}</div>
                  <h3 className="project-title">{project.title}</h3>
                </div>
                <div className="project-description">
                  <p>{project.description}</p>
                </div>
                <div className="project-tags">
                  {project.tags.map((tag, tagIndex) => (
                    <span key={tagIndex} className="tag">{tag}</span>
                  ))}
                </div>
                <div className="project-action">
                  <a href="#" className="view-project">
                    <span>View Case Study</span>
                    <div className="arrow-icon">→</div>
                  </a>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};

export default Projects;
